private bool CanAddAttachments()
{
    if (SelectedTask is null || ShowArchive)
        return false;

    if (_runningTaskIds.Contains(SelectedTask.Id))
        return false;

    if (_rewritingTaskIds.Contains(SelectedTask.Id))
        return false;

    return true;
}

// ── Reflection helpers for private members ──────────────────────────

private static MethodInfo GetBeginRunningTaskMethod()
{
    return typeof(MainWindowViewModel)
        .GetMethod("BeginRunningTask", BindingFlags.NonPublic | BindingFlags.Instance)!;
}

private static MethodInfo GetClearRunningTaskMethod()
{
    return typeof(MainWindowViewModel)
        .GetMethod("ClearRunningTask", BindingFlags.NonPublic | BindingFlags.Instance)!;
}

private static void AddToRewritingTaskIds(MainWindowViewModel vm, string taskId)
{
    var field = typeof(MainWindowViewModel)
        .GetField("_rewritingTaskIds", BindingFlags.NonPublic | BindingFlags.Instance)!;
    var set = (HashSet<string>)field.GetValue(vm)!;
    set.Add(taskId);
}

private static void RemoveFromRewritingTaskIds(MainWindowViewModel vm, string taskId)
{
    var field = typeof(MainWindowViewModel)
        .GetField("_rewritingTaskIds", BindingFlags.NonPublic | BindingFlags.Instance)!;
    var set = (HashSet<string>)field.GetValue(vm)!;
    set.Remove(taskId);
}

private static void RaiseRewriteStateChanged(MainWindowViewModel vm)
{
    var method = typeof(MainWindowViewModel)
        .GetMethod("RaiseRewriteStateChanged", BindingFlags.NonPublic | BindingFlags.Instance)!;
    method.Invoke(vm, null);
}

